1	'use client';
2	
3	import React, { useState, useEffect, useRef, useCallback } from 'react';
4	import dynamic from 'next/dynamic';
5	import { Send, Mic, MicOff, Volume2, VolumeX, Loader2, AlertCircle } from 'lucide-react';
6	import ReactMarkdown from 'react-markdown';
7	import remarkGfm from 'remark-gfm';
8	
9	const NeuralBrain = dynamic(() => import('@/components/NeuralBrain'), { ssr: false });
10	
11	// ── types ──────────────────────────────────────────────────────────────────
12	interface Message {
13	  id: string;
14	  role: 'user' | 'assistant';
15	  content: string;
16	}
17	
18	// ── speech recognition types ──────────────────────────────────────────────
19	type SRInstance = {
20	  lang: string;
21	  continuous: boolean;
22	  interimResults: boolean;
23	  onresult: ((e: SREvent) => void) | null;
24	  onerror: ((e: Event) => void) | null;
25	  onend: (() => void) | null;
26	  start(): void;
27	  stop(): void;
28	  abort(): void;
29	};
30	type SREvent = { results: { length: number; [i: number]: { isFinal: boolean; [j: number]: { transcript: string } } } };
31	
32	function getSR(): (new () => SRInstance) | null {
33	  if (typeof window === 'undefined') return null;
34	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
35	  const w = window as any;
36	  return w.SpeechRecognition || w.webkitSpeechRecognition || null;
37	}
38	
39	// ── TTS ────────────────────────────────────────────────────────────────────
40	function speak(text: string): void {
41	  if (typeof window === 'undefined' || !window.speechSynthesis) return;
42	  window.speechSynthesis.cancel();
43	  const utter = new SpeechSynthesisUtterance(text);
44	  utter.rate = 1.0;
45	  utter.pitch = 1.0;
46	  utter.volume = 1.0;
47	  // Pick a good English voice; fall back to whatever is available
48	  const pickVoice = () => {
49	    const voices = window.speechSynthesis.getVoices();
50	    return (
51	      voices.find(v => v.name.toLowerCase().includes('google') && v.lang.startsWith('en')) ||
52	      voices.find(v => v.lang.startsWith('en')) ||
53	      voices[0]
54	    );
55	  };
56	  const v = pickVoice();
57	  if (v) utter.voice = v;
58	  window.speechSynthesis.speak(utter);
59	}
60	
61	// ── stream parser ──────────────────────────────────────────────────────────
62	// Handles both Vercel AI SDK (0:"chunk") and plain-text (Firebase / Gemini) streams
63	function parseChunk(chunk: string): string {
64	  let out = '';
65	  for (const line of chunk.split('\n')) {
66	    if (line.startsWith('0:')) {
67	      try {
68	        const delta = JSON.parse(line.slice(2));
69	        if (typeof delta === 'string') out += delta;
70	      } catch { /* skip malformed */ }
71	    } else if (
72	      line.trim() &&
73	      !line.startsWith('e:') &&
74	      !line.startsWith('d:') &&
75	      !line.startsWith('data:') &&
76	      !line.startsWith('f:') &&
77	      !line.startsWith('8:') &&
78	      !line.startsWith('2:')
79	    ) {
80	      out += line;
81	    }
82	  }
83	  return out;
84	}
85	
86	// ── component ──────────────────────────────────────────────────────────────
87	export default function ChatPage() {
88	  const [messages, setMessages]     = useState<Message[]>([]);
89	  const [input, setInput]           = useState('');
90	  const [isStreaming, setIsStreaming] = useState(false);
91	  const [isListening, setIsListening] = useState(false);
92	  const [ttsEnabled, setTtsEnabled]  = useState(true);
93	  const [transcript, setTranscript]  = useState('');
94	  const [error, setError]            = useState<string | null>(null);
95	
96	  const messagesEndRef = useRef<HTMLDivElement>(null);
97	  const recognitionRef = useRef<SRInstance | null>(null);
98	  const abortRef       = useRef<AbortController | null>(null);
99	  const textareaRef    = useRef<HTMLTextAreaElement>(null);
100	
101	  // Load TTS voices eagerly (Chrome lazy-loads them)
102	  useEffect(() => {
103	    const load = () => window.speechSynthesis?.getVoices();
104	    load();
105	    window.speechSynthesis?.addEventListener?.('voiceschanged', load);
106	    return () => window.speechSynthesis?.removeEventListener?.('voiceschanged', load);
107	  }, []);
108	
109	  // Auto-scroll on new messages
110	  useEffect(() => {
111	    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
112	  }, [messages]);
113	
114	  // Auto-resize textarea
115	  useEffect(() => {
116	    const ta = textareaRef.current;
117	    if (!ta) return;
118	    ta.style.height = 'auto';
119	    ta.style.height = Math.min(ta.scrollHeight, 140) + 'px';
120	  }, [input]);
121	
122	  // ── send ─────────────────────────────────────────────────────────────────
123	  const sendMessage = useCallback(async (text: string) => {
124	    const trimmed = text.trim();
125	    if (!trimmed || isStreaming) return;
126	
127	    setError(null);
128	    setInput('');
129	    setTranscript('');
130	
131	    const userMsg: Message = { id: `u-${Date.now()}`, role: 'user', content: trimmed };
132	    const history = [...messages, userMsg];
133	    setMessages(history);
134	    setIsStreaming(true);
135	
136	    const assistantId = `a-${Date.now()}`;
137	    setMessages(prev => [...prev, { id: assistantId, role: 'assistant', content: '' }]);
138	
139	    try {
140	      abortRef.current?.abort();
141	      const abort = new AbortController();
142	      abortRef.current = abort;
143	
144	      const res = await fetch('/api/chat/stream', {
145	        method: 'POST',
146	        headers: { 'Content-Type': 'application/json' },
147	        body: JSON.stringify({ messages: history.map(m => ({ role: m.role, content: m.content })) }),
148	        signal: abort.signal,
149	      });
150	
151	      if (!res.ok) {
152	        const body = await res.text().catch(() => '');
153	        throw new Error(`HTTP ${res.status}: ${body.slice(0, 120)}`);
154	      }
155	
156	      const reader = res.body?.getReader();
157	      const decoder = new TextDecoder();
158	      let accumulated = '';
159	
160	      if (reader) {
161	        while (true) {
162	          const { done, value } = await reader.read();
163	          if (done) break;
164	          const delta = parseChunk(decoder.decode(value, { stream: true }));
165	          if (delta) {
166	            accumulated += delta;
167	            setMessages(prev =>
168	              prev.map(m => m.id === assistantId ? { ...m, content: accumulated } : m)
169	            );
170	          }
171	        }
172	      }
173	
174	      // TTS — speak the complete response
175	      if (ttsEnabled && accumulated) {
176	        // Small delay so the UI settles first
177	        setTimeout(() => speak(accumulated), 80);
178	      }
179	    } catch (err) {
180	      if ((err as Error).name !== 'AbortError') {
181	        const msg = (err as Error).message;
182	        setError(msg.includes('quota') ? 'AI quota exhausted — check provider config' : `Neural link error: ${msg}`);
183	        setMessages(prev => prev.filter(m => m.id !== assistantId));
184	      }
185	    } finally {
186	      setIsStreaming(false);
187	      abortRef.current = null;
188	    }
189	  // eslint-disable-next-line react-hooks/exhaustive-deps
190	  }, [messages, isStreaming, ttsEnabled]);
191	
192	  // ── STT ──────────────────────────────────────────────────────────────────
193	  const startListening = useCallback(() => {
194	    const SR = getSR();
195	    if (!SR) { setError('Speech recognition not supported in this browser (try Chrome)'); return; }
196	
197	    // Cancel TTS while user speaks
198	    window.speechSynthesis?.cancel();
199	
200	    const rec = new SR();
201	    rec.lang = 'en-US';
202	    rec.continuous = false;
203	    rec.interimResults = true;
204	
205	    rec.onresult = (e: SREvent) => {
206	      let interim = '';
207	      let final = '';
208	      for (let i = 0; i < e.results.length; i++) {
209	        const r = e.results[i];
210	        if (r.isFinal) final += r[0].transcript;
211	        else interim += r[0].transcript;
212	      }
213	      setTranscript(final || interim);
214	      if (final) {
215	        rec.stop();
216	        setIsListening(false);
217	        sendMessage(final);
218	      }
219	    };
220	
221	    rec.onerror = (e: Event) => {
222	      const code = (e as unknown as { error: string }).error;
223	      setIsListening(false);
224	      if (code !== 'aborted') setError(`Mic error: ${code}`);
225	    };
226	
227	    rec.onend = () => setIsListening(false);
228	
229	    rec.start();
230	    recognitionRef.current = rec;
231	    setIsListening(true);
232	    setError(null);
233	  }, [sendMessage]);
234	
235	  const stopListening = useCallback(() => {
236	    recognitionRef.current?.abort();
237	    setIsListening(false);
238	    setTranscript('');
239	  }, []);
240	
241	  const toggleMic = () => {
242	    if (isListening) stopListening();
243	    else startListening();
244	  };
245	
246	  const toggleTTS = () => {
247	    if (ttsEnabled) window.speechSynthesis?.cancel();
248	    setTtsEnabled(s => !s);
249	  };
250	
251	  const handleKeyDown = (e: React.KeyboardEvent) => {
252	    if (e.key === 'Enter' && !e.shiftKey) {
253	      e.preventDefault();
254	      sendMessage(input);
255	    }
256	  };
257	
258	  const isEmpty = messages.length === 0;
259	  const lastMsg = messages[messages.length - 1];
260	
261	  return (
262	    <div className="omega-root">
263	      {/* Neural canvas background */}
264	      <div className="omega-bg">
265	        <NeuralBrain isActive={isStreaming || isListening} />
266	      </div>
267	
268	      {/* ── Header ── */}
269	      <header className="omega-header">
270	        <div className="omega-logo">
271	          <span className="omega-symbol">Ω</span>
272	        </div>
273	        <span className="omega-brand">Chyren</span>
274	
275	        <div className="omega-header-status">
276	          <span className={`omega-status-dot ${(isStreaming || isListening) ? 'omega-status-active' : ''}`} />
277	          <span className="omega-status-label">
278	            {isStreaming ? 'PROCESSING' : isListening ? 'LISTENING' : 'SOVEREIGN'}
279	          </span>
280	        </div>
281	
282	        <div className="omega-header-actions">
283	          <button onClick={toggleTTS} className="omega-icon-btn" title={ttsEnabled ? 'Mute Chyren' : 'Enable voice'}>
284	            {ttsEnabled ? <Volume2 size={15} /> : <VolumeX size={15} />}
285	          </button>
286	        </div>
287	      </header>
288	
289	      {/* ── Main ── */}
290	      <main className="omega-main">
291	        {isEmpty ? (
292	          <div className="omega-idle">
293	            <div className="omega-idle-title">
294	              <span className="omega-idle-omega">Ω</span>
295	              <span className="omega-idle-name">Chyren</span>
296	            </div>
297	            <p className="omega-idle-sub">SOVEREIGN INTELLIGENCE ORCHESTRATOR</p>
298	            <p className="omega-idle-desc">
299	              High-integrity cognitive processing and neural telemetry. Speak or type to initiate a session.
300	            </p>
301	
302	            {/* Voice orb */}
303	            <button
304	              className={`omega-orb ${isListening ? 'omega-orb-active' : ''}`}
305	              onClick={toggleMic}
306	              disabled={isStreaming}
307	              aria-label="Voice input"
308	            >
309	              <div className="omega-orb-ring omega-orb-ring-1" />
310	              <div className="omega-orb-ring omega-orb-ring-2" />
311	              <div className="omega-orb-ring omega-orb-ring-3" />
312	              <div className="omega-orb-core">
313	                {isListening ? <MicOff size={26} /> : <Mic size={26} />}
314	              </div>
315	            </button>
316	
317	            <p className="omega-orb-label">
318	              {isListening ? 'LISTENING — SPEAK NOW' : 'INITIALIZE NEURAL INTENT'}
319	            </p>
320	
321	            {transcript && <p className="omega-transcript">{transcript}</p>}
322	          </div>
323	        ) : (
324	          <div className="omega-messages">
325	            {messages.map(msg => (
326	              <div key={msg.id} className={`omega-msg omega-msg-${msg.role}`}>
327	                <div className="omega-msg-label">
328	                  {msg.role === 'user' ? '▸ OPERATOR' : 'Ω CHYREN'}
329	                </div>
330	                <div className="omega-msg-content">
331	                  {msg.role === 'assistant' ? (
332	                    <>
333	                      <ReactMarkdown remarkPlugins={[remarkGfm]}>{msg.content}</ReactMarkdown>
334	                      {isStreaming && msg === lastMsg && <span className="omega-cursor" />}
335	                    </>
336	                  ) : (
337	                    <p>{msg.content}</p>
338	                  )}
339	                </div>
340	              </div>
341	            ))}
342	            {/* Transcript bar while listening mid-conversation */}
343	            {isListening && transcript && (
344	              <p className="omega-transcript-bar">{transcript}</p>
345	            )}
346	            <div ref={messagesEndRef} />
347	          </div>
348	        )}
349	
350	        {error && (
351	          <div className="omega-error">
352	            <AlertCircle size={13} />
353	            <span>{error}</span>
354	            <button className="omega-error-dismiss" onClick={() => setError(null)}>✕</button>
355	          </div>
356	        )}
357	      </main>
358	
359	      {/* ── Footer / input ── */}
360	      <footer className="omega-footer">
361	        <div className="omega-input-wrap">
362	          <button
363	            className={`omega-voice-btn ${isListening ? 'omega-voice-btn-active' : ''}`}
364	            onClick={toggleMic}
365	            disabled={isStreaming}
366	            aria-label={isListening ? 'Stop listening' : 'Start voice input'}
367	          >
368	            {isListening ? <MicOff size={17} /> : <Mic size={17} />}
369	          </button>
370	
371	          <textarea
372	            ref={textareaRef}
373	            className="omega-textarea"
374	            value={isListening ? (transcript || '') : input}
375	            onChange={e => setInput(e.target.value)}
376	            onKeyDown={handleKeyDown}
377	            placeholder="▸  transmit cognitive intent..."
378	            rows={1}
379	            disabled={isStreaming || isListening}
380	          />
381	
382	          <button
383	            className="omega-send-btn"
384	            onClick={() => sendMessage(input)}
385	            disabled={isStreaming || isListening || !input.trim()}
386	            aria-label="Send"
387	          >
388	            {isStreaming ? <Loader2 size={17} className="omega-spin" /> : <Send size={17} />}
389	          </button>
390	        </div>
391	
392	        <div className="omega-footer-meta">
393	          <span className="omega-footer-label">NEURAL LINK</span>
394	          <span className={`omega-footer-dot ${isStreaming ? 'omega-footer-dot-active' : ''}`} />
395	          <span className="omega-footer-label">{isStreaming ? 'ACTIVE' : 'STANDBY'}</span>
396	        </div>
397	      </footer>
398	    </div>
399	  );
400	}
