1	'use client'
2	
3	import React, { useRef, useState, useCallback, useEffect } from 'react'
4	import { useVoiceEngine } from '@/hooks/useVoiceEngine'
5	
6	interface ChatInputProps {
7	  onSend: (message: string) => void
8	  disabled?: boolean
9	  isLoading?: boolean
10	}
11	
12	export function ChatInput({ onSend, disabled = false, isLoading = false }: ChatInputProps) {
13	  const [input, setInput] = useState('')
14	  const textareaRef = useRef<HTMLTextAreaElement>(null)
15	
16	  const handleTranscript = useCallback((text: string) => {
17	    setInput((prev) => (prev ? prev + ' ' + text : text))
18	  }, [])
19	
20	  const { isRecording, startRecording, stopRecording } = useVoiceEngine(handleTranscript)
21	
22	  useEffect(() => {
23	    if (textareaRef.current) {
24	      textareaRef.current.style.height = '22px'
25	      textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 120) + 'px'
26	    }
27	  }, [input])
28	
29	  const handleSend = useCallback(() => {
30	    if (input.trim() && !disabled && !isLoading) {
31	      onSend(input.trim())
32	      setInput('')
33	      if (textareaRef.current) textareaRef.current.style.height = '22px'
34	    }
35	  }, [input, disabled, isLoading, onSend])
36	
37	  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
38	    if (e.key === 'Enter' && !e.shiftKey) {
39	      e.preventDefault()
40	      handleSend()
41	    }
42	  }
43	
44	  return (
45	    <div className="input-area rounded-lg px-4 py-3 flex items-end gap-3">
46	      {/* Prompt glyph */}
47	      <span
48	        className="font-mono text-sm flex-shrink-0 pb-0.5 select-none"
49	        style={{ color: '#6366f1' }}
50	      >
51	        ▸
52	      </span>
53	
54	      <textarea
55	        ref={textareaRef}
56	        value={input}
57	        onChange={(e) => setInput(e.target.value)}
58	        onKeyDown={handleKeyDown}
59	        placeholder="Enter command or query…"
60	        disabled={disabled || isLoading}
61	        className="flex-1 bg-transparent font-mono text-sm text-slate-200 placeholder-slate-700 resize-none focus:outline-none disabled:opacity-40 leading-relaxed"
62	        rows={1}
63	        style={{ minHeight: '22px' }}
64	      />
65	
66	      {/* Voice */}
67	      <button
68	        onClick={isRecording ? stopRecording : startRecording}
69	        disabled={disabled || isLoading}
70	        className="flex-shrink-0 w-7 h-7 rounded flex items-center justify-center transition-all duration-150 disabled:opacity-30"
71	        style={{
72	          background: isRecording ? 'rgba(248,113,113,0.15)' : 'rgba(99,102,241,0.1)',
73	          border: `1px solid ${isRecording ? 'rgba(248,113,113,0.4)' : 'rgba(99,102,241,0.2)'}`,
74	          color: isRecording ? '#f87171' : '#818cf8',
75	        }}
76	        title={isRecording ? 'Stop recording' : 'Voice input'}
77	      >
78	        {isRecording ? (
79	          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20">
80	            <rect x="5" y="5" width="3.5" height="10" rx="1"/>
81	            <rect x="11.5" y="5" width="3.5" height="10" rx="1"/>
82	          </svg>
83	        ) : (
84	          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20">
85	            <path d="M10 2a3 3 0 0 0-3 3v5a3 3 0 0 0 6 0V5a3 3 0 0 0-3-3zM7 14.5A5 5 0 0 0 15 10h-1.5a3.5 3.5 0 0 1-7 0H5a5 5 0 0 0 5 4.5V16H8v1.5h4V16h-2v-1.5z"/>
86	          </svg>
87	        )}
88	      </button>
89	
90	      {/* Send */}
91	      <button
92	        onClick={handleSend}
93	        disabled={!input.trim() || disabled || isLoading}
94	        className="flex-shrink-0 w-7 h-7 rounded flex items-center justify-center transition-all duration-150 disabled:opacity-20"
95	        style={{
96	          background: 'rgba(99,102,241,0.15)',
97	          border: '1px solid rgba(99,102,241,0.35)',
98	          color: '#818cf8',
99	        }}
100	        title="Send (Enter)"
101	      >
102	        {isLoading ? (
103	          <svg className="w-3 h-3 animate-spin" fill="none" viewBox="0 0 24 24">
104	            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3"/>
105	            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
106	          </svg>
107	        ) : (
108	          <svg className="w-3 h-3" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
109	            <path strokeLinecap="round" strokeLinejoin="round" d="M5 12h14M12 5l7 7-7 7"/>
110	          </svg>
111	        )}
112	      </button>
113	    </div>
114	  )
115	}
