1	import { NextRequest, NextResponse } from 'next/server'
2	
3	export async function POST(req: NextRequest) {
4	  try {
5	    const body = await req.json()
6	    const { message } = body
7	
8	    if (!message) {
9	      return NextResponse.json({ error: 'Message is required' }, { status: 400 })
10	    }
11	
12	    // Mock response for now
13	    const response = `Echo: ${message}`
14	    return NextResponse.json({ response })
15	  } catch (error) {
16	    console.error('Chat error:', error)
17	    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
18	  }
19	}
