232	          const delta = parseChunk(decoder.decode(value, { stream: true }));
233	          if (delta) {
234	            accumulated += delta;
235	            setMessages(prev =>
236	              prev.map(m => m.id === assistantId ? { ...m, content: accumulated } : m)
237	            );
