264	  // ── STT ──────────────────────────────────────────────────────────────────
265	  const startListening = useCallback(async () => {
266	    audioRef.current?.pause();
267	    audioRef.current = null;
268	    window.speechSynthesis?.cancel();
269	
270	    const SR = getSR();
271	    if (!SR) {
272	      try {
273	        const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
274	        mediaStreamRef.current = stream;
275	        audioChunksRef.current = [];
276	
277	        const preferredMimeType = MediaRecorder.isTypeSupported('audio/webm;codecs=opus')
278	          ? 'audio/webm;codecs=opus'
279	          : 'audio/webm';
280	        const recorder = new MediaRecorder(stream, { mimeType: preferredMimeType });
281	        mediaRecorderRef.current = recorder;
282	
283	        recorder.ondataavailable = (event) => {
284	          if (event.data.size > 0) {
285	            audioChunksRef.current.push(event.data);
286	          }
287	        };
288	
289	        recorder.onstop = async () => {
290	          mediaStreamRef.current?.getTracks().forEach(track => track.stop());
291	          mediaStreamRef.current = null;
292	          mediaRecorderRef.current = null;
293	
294	          const audioBlob = new Blob(audioChunksRef.current, { type: preferredMimeType });
295	          audioChunksRef.current = [];
296	          if (!audioBlob.size) {
297	            setTranscript('');
298	            return;
299	          }
300	
301	          setTranscript('Transcribing...');
302	          try {
303	            const finalTranscript = await transcribeAudio(audioBlob);
304	            setTranscript(finalTranscript);
305	            await sendMessage(finalTranscript);
306	          } catch (err) {
307	            setError((err as Error).message);
308	          }
309	        };
310	
311	        recorder.start();
312	        setTranscript('Listening...');
313	        setIsListening(true);
314	        setError(null);
315	      } catch (err) {
316	        setError(`Mic error: ${(err as Error).message}`);
317	      }
318	      return;
319	    }
320	
321	    const rec = new SR();
322	    rec.lang = 'en-US';
323	    rec.continuous = false;
324	    rec.interimResults = true;
325	
326	    rec.onresult = (e: SREvent) => {
327	      let interim = '';
328	      let final = '';
329	      for (let i = 0; i < e.results.length; i++) {
330	        const r = e.results[i];
331	        if (r.isFinal) final += r[0].transcript;
332	        else interim += r[0].transcript;
333	      }
