1	/**
2	 * ADCCL: Anti-Drift Cognitive Control Loop (TypeScript Port)
3	 * 
4	 * Verifies provider responses for drift, hallucinations, and stubs.
5	 */
6	
7	const STUB_PATTERNS = [
8	  /\bTODO\b/i,
9	  /\bFIXME\b/i,
10	  /\bPLACEHOLDER\b/i,
11	  /\[INSERT[^\]]*\]/i,
12	  /\[YOUR[^\]]*\]/i,
13	  /<YOUR[^>]*>/i,
14	  /\.{5,}/
15	];
16	
17	const HALLUCINATION_ANCHORS = [
18	  /as of my (last|latest) (training|knowledge) (update|cutoff)/i,
19	  /I (don't|do not) have (access|the ability) to (browse|access|search)/i,
20	  /I (cannot|can't) (verify|confirm|check) (this|that|if)/i
21	];
22	
23	const REFUSAL_PATTERNS = [
24	  /^I('m| am) (sorry|unable|not able)/i,
25	  /^(Sorry|Apologies),? (but )?I (can't|cannot|am unable)/i,
26	  /^I (don't|do not) have (the capability|access|the ability)/i
27	];
28	
29	const MIN_LENGTH = 20;
30	const MAX_LENGTH = 32000;
31	
32	export interface VerificationResult {
33	  passed: boolean;
34	  score: number;
35	  flags: string[];
36	}
37	
38	export class ADCCL {
39	  private minScore: number;
40	
41	  constructor(minScore: number = 0.7) {
42	    this.minScore = minScore;
43	  }
44	
45	  public verify(responseText: string, task: string = ""): VerificationResult {
46	    const flags: string[] = [];
47	    const text = responseText.trim();
48	
49	    if (!text) flags.push("EMPTY_RESPONSE");
50	    if (text.length < MIN_LENGTH) flags.push(`RESPONSE_TOO_SHORT (len=${text.length})`);
51	    if (responseText.length > MAX_LENGTH) flags.push(`RESPONSE_EXCEEDS_MAX_LENGTH (len=${responseText.length})`);
52	
53	    if (STUB_PATTERNS.some(p => p.test(responseText))) flags.push("STUB_MARKERS_DETECTED");
54	    if (HALLUCINATION_ANCHORS.some(p => p.test(responseText))) flags.push("HALLUCINATION_ANCHORS");
55	    if (REFUSAL_PATTERNS.some(p => p.test(text)) && text.length < 150) flags.push("PURE_CAPABILITY_REFUSAL");
56	
57	    if (task) {
58	      const taskWords = new Set(task.toLowerCase().match(/\b\w{5,}\b/g) || []);
59	      const responseWords = new Set(text.toLowerCase().match(/\b\w{5,}\b/g) || []);
60	      const overlap = [...taskWords].filter(w => responseWords.has(w));
61	      if (taskWords.size > 0 && overlap.length === 0) flags.push("NO_TASK_WORD_OVERLAP");
62	    }
63	
64	    const checksTotal = 7;
65	    const checksPassed = checksTotal - flags.length;
66	    const score = Math.round(Math.max(0, checksPassed / checksTotal) * 100) / 100;
67	    
68	    const hardVetoPrefixes = ["EMPTY_RESPONSE", "STUB_MARKERS_DETECTED", "PURE_CAPABILITY_REFUSAL"];
69	    const passed = score >= this.minScore && !flags.some(f => hardVetoPrefixes.some(v => f.startsWith(v)));
70	
71	    return { passed, score, flags };
72	  }
73	}
