import { getCache } from '@vercel/functions'
import { NextRequest } from 'next/server'

const RATE_LIMIT_MAX = 20
const RATE_LIMIT_WINDOW_MS = 60_000

// Falls back to in-memory when Runtime Cache is unavailable (local dev)
const localStore = new Map<string, number[]>()

export async function checkRateLimit(ip: string): Promise<boolean> {
  const now = Date.now()
  const key = `ratelimit:${ip}`

  try {
    const cache = getCache({ namespace: 'hardening' })
    const stored = await cache.get<number[]>(key)
    const timestamps: number[] = (stored ?? []).filter(t => now - t < RATE_LIMIT_WINDOW_MS)

    if (timestamps.length >= RATE_LIMIT_MAX) return false

    timestamps.push(now)
    await cache.set(key, timestamps, {
      ttl: Math.ceil(RATE_LIMIT_WINDOW_MS / 1000) + 1,
      tags: ['ratelimit'],
    })
    return true
  } catch {
    // Runtime Cache unavailable (local dev) — fall back to in-memory
    const timestamps = (localStore.get(key) ?? []).filter(t => now - t < RATE_LIMIT_WINDOW_MS)
    if (timestamps.length >= RATE_LIMIT_MAX) return false
    timestamps.push(now)
    localStore.set(key, timestamps)
    return true
  }
}

export function validateChatRequest(req: NextRequest): boolean {
  return Boolean(req.headers.get('origin'))
}

export function checkPromptInjection(input: string): boolean {
  const injections = ['ignore previous instructions', 'system override']
  return injections.some(i => input.toLowerCase().includes(i))
}

import { getCache } from '@vercel/functions'

export interface BrainState {
  adccl: number
  provider: number
  threat: number
  phylactery: number
  ledger: number
  alignment: number
  stage: string
}

export const IDLE_STATE: BrainState = {
  adccl: 0.05,
  provider: 0.05,
  threat: 0.02,
  phylactery: 0.08,
  ledger: 0.02,
  alignment: 0.05,
  stage: 'idle',
}

// Local fallback for dev environments where Runtime Cache is unavailable
const localStore = new Map<string, BrainState>()

export async function setBrainState(session: string, state: Partial<BrainState>): Promise<void> {
  try {
    const cache = getCache({ namespace: 'brain' })
    const current = await cache.get<BrainState>(session) ?? { ...IDLE_STATE }
    const next = { ...current, ...state }
    await cache.set(session, next, { ttl: 60, tags: ['brain-state'] })
  } catch {
    const current = localStore.get(session) ?? { ...IDLE_STATE }
    localStore.set(session, { ...current, ...state })
  }
}

export async function getBrainState(session: string): Promise<BrainState> {
  try {
    const cache = getCache({ namespace: 'brain' })
    return await cache.get<BrainState>(session) ?? { ...IDLE_STATE }
  } catch {
    return localStore.get(session) ?? { ...IDLE_STATE }
  }
}

